using namespace std;

struct node

{

	int a,b;

}p[200005];

int n;

bool cmp(node x,node y)

{

	return x.a<y.a;

}

int main()

{

	scanf("%d",&n);

	for(int i=1;i<=n;i++)

	{

		scanf("%d%d",&p[i].a,&p[i].b);

		if(p[i].a>p[i].b) swap(p[i].a,p[i].b);

	}

	sort(p+1,p+n+1,cmp);

	int minx=p[1].a,maxx=p[1].b;

	for(int i=2;i<=n;i++)

	{

		minx=max(minx,p[i].a);

		maxx=min(maxx,p[i].b);

	}

	int ans=maxx-minx;

	if(ans<0) ans=0;

	int miny=p[1].b,maxy=p[1].a;

	for(int i=2;i<=n;i++)

	{

		miny=max(miny,p[i].b);

		maxy=min(maxy,p[i].a);

	}

	int ans2=maxy-miny;

	if(ans2<0) ans2=0;

	printf("%d\n",min(ans*(p[n].b-p[n].a),ans2*(maxx-minx)));

	return 0;

}

